];

function hasDeploymentConfig(tree) {
  return tree.some(p => {
    const lower = p.toLowerCase();
    return /^dockerfile/i.test(lower) ||
      /^docker-compose\.(yml|yaml)$/i.test(lower) ||
      /^fly\.toml$/i.test(lower) ||
      /^wrangler\.(toml|json)$/i.test(lower) ||
      /^serverless\.(yml|yaml|json|ts)$/i.test(lower) ||
      /^captain-definition$/i.test(lower) ||
      /^Procfile$/i.test(lower) ||
      (/(^|\/)(k8s|kubernetes|helm|deploy|infra)\//i.test(p) && /\.(ya?ml|yaml|json|toml)$/i.test(lower));
  });
}

function hasKubernetesManifests(tree) {
  return tree.some(p => /(^|\/)(k8s|kubernetes|helm|deploy|infra)\//i.test(p) && /\.(ya?ml|yaml|json)$/i.test(p));
}

function hasStartScript(packageJson) {
  if (!packageJson?.scripts) return false;
  const s = packageJson.scripts;
  return !!(s.start || s.serve || s.deploy || s.preview || s['start:prod'] || s['start:production']);
}

function hasServerDependency(packageJson) {
  if (!packageJson) return false;
  const serverDeps = ['express', 'fastify', 'koa', 'hapi', '@hapi/hapi', 'micro', 'next', 'nuxt', 'astro', 'remix', 'nitropack', 'nitro', 'h3', 'hono', 'elysia', '@nestjs/core', 'connect', 'polka', 'restify', 'serve-static', 'webpack-dev-server'];
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies, ...packageJson.peerDependencies };
  return Object.keys(deps).some(d => serverDeps.includes(d));
}

function isFrameworkSource(packageJson, tree, repoType) {
  const hasPackages = tree.some(p => /^packages\/[^/]+\//i.test(p));
  const hasApps = tree.some(p => /^apps\/[^/]+\//i.test(p));
  const hasExamples = tree.some(p => /^(examples?|playground|fixtures?|demos?|starters?)\//i.test(p));
  const hasNoDeployment = !hasDeploymentConfig(tree);

  if (repoType === 'framework') {
    if (hasPackages && !hasApps) return true;
    if (hasExamples && hasNoDeployment) return true;
    if (hasNoDeployment && !hasStartScript(packageJson)) return true;
  }

  if (hasPackages && !hasApps && hasNoDeployment && hasExamples) return true;
  if (packageJson?.private && packageJson?.workspaces && hasPackages && !hasApps && hasNoDeployment) return true;

  return false;
}

function isTutorialRepo(tree, packageJson) {
  const allPkgJson = tree.filter(p => /(^|\/)package\.json$/i.test(p));
  const rootPkg = allPkgJson.some(p => p === 'package.json');
  const subPkgs = allPkgJson.filter(p => p !== 'package.json');

  if (rootPkg && subPkgs.length >= 4) {
    const inLearnDirs = subPkgs.filter(p => /^(examples?|starters?|templates?|demos?|playground|learn|chapters?|lessons?|tutorials?|course|workshop)\//i.test(p)).length;
    if (inLearnDirs >= 2 || subPkgs.length >= 6) return true;
  }

  const learnDirs = ['examples', 'example', 'starters', 'starter', 'templates', 'template', 'demos', 'demo', 'playground', 'learn', 'chapters', 'lessons', 'tutorial', 'tutorials', 'course', 'workshop'];
  for (const dir of learnDirs) {
    const projects = tree.filter(p => new RegExp(`^${dir}/[^/]+/package\\.json$`, 'i').test(p));
    if (projects.length >= 2) return true;
  }

  return false;
}

function isStaticOrPlatformManaged(tree, packageJson) {
  if (hasStartScript(packageJson)) return false;

  const hasServerFiles = tree.some(p => /^(src\/)?(server|app|main|index)\.(js|ts|mjs|cjs)$/i.test(p)) ||
    tree.some(p => /(^|\/)((app|pages)\/api|api\/|server\/api|src\/api|workers\/|functions\/|controllers\/|handlers\/)\//i.test(p));

  if (hasServerFiles) return false;

  const managedFrameworks = ['next', 'nuxt', 'astro', '@astrojs/node', 'remix', '@sveltejs/kit', 'svelte'];
  const deps = { ...packageJson?.dependencies, ...packageJson?.devDependencies };
  const usesManaged = Object.keys(deps).some(d => managedFrameworks.includes(d));

  if (usesManaged && !hasDeploymentConfig(tree)) return true;

  return false;
}

function findHealthDependency(packageJson) {
  if (!packageJson) return null;
  const deps = { ...packageJson.dependencies, ...packageJson.devDependencies, ...packageJson.peerDependencies };
  return Object.keys(deps).find(d => HEALTH_LIBS.has(d)) || null;
}

function scoreServerFile(path) {
  let score = 0;
  const lower = path.toLowerCase();
  const basename = lower.split('/').pop();

  if (/^(src\/)?(server|app|main|index)\.(js|ts|mjs|cjs)$/.test(path)) score += 15;
  if (/(^|\/)((app|pages)\/api|api\/)/.test(path)) score += 12;
  if (/(^|\/)((src\/)?api|server\/api)\//.test(path)) score += 10;
  if (/(^|\/)((src\/)?routes|server|routes)\//.test(path)) score += 8;
  if (/(^|\/)((src\/)?(controllers|handlers|middleware|backend|workers))\//.test(path)) score += 7;
  if (/(^|\/)((netlify|supabase|edge)[-_]?functions|functions)\//.test(path)) score += 8;
  if (/\.(route|router|controller|handler|endpoint|middleware)\./.test(basename)) score += 5;
  if (path.startsWith('src/')) score += 2;

  if (/\.(test|spec)\./.test(path)) score -= 25;
  if (/(__tests__|__mocks__|fixtures?|examples?|demo|playground|benchmark|docs|\.github|\.storybook|scripts|dist|build|coverage|storybook|bin|cli|config|vitest|jest|knip|lint|\.vscode)\//i.test(path)) score -= 15;
  if (/node_modules/.test(path)) score -= 50;
  if (/\.d\.ts$/.test(path)) score -= 30;

  const depth = path.split('/').length;
  if (depth > 6) score -= 3;
  if (depth > 10) score -= 6;

  return score;
}

